function stableId(value) {
  const text = String(value || '');
  let hash = 0;
  for (let index = 0; index < text.length; index += 1) {
    hash = ((hash << 5) - hash + text.charCodeAt(index)) | 0;
  }
  return 'id_' + Math.abs(hash).toString(36) + '_' + text.length.toString(36);
}

function asText(value) {
  if (value == null) return '';
  if (Array.isArray(value)) return value.map(asText).filter(Boolean).join(', ');
  if (typeof value === 'object') return JSON.stringify(value);
  return String(value);
}

function pickBudget(job) {
  const budget = job.budget || {};
  if (typeof budget === 'string') return budget;
  if (!budget || typeof budget !== 'object') return '';
  return Object.entries(budget)
    .map(([key, value]) => `${key}: ${asText(value)}`)
    .join('; ');
}

const rows = [];

for (const item of items) {
  const job = item.json;
  const sourceUrl = job.externalLink || job.url || job.link || '';
  const uid = job.uid || sourceUrl || `${job.title || ''}|${job.publishedAt || job.createdAt || ''}`;
  const externalId = stableId(uid);
  const budgetText = pickBudget(job);
  const skillsText = asText(job.skills);
  const clientText = asText(job.client);
  const vendorText = asText(job.vendor);
  const descriptionParts = [
    job.description || '',
    budgetText ? `Budget: ${budgetText}` : '',
    skillsText ? `Skills: ${skillsText}` : '',
    clientText ? `Client: ${clientText}` : '',
    vendorText ? `Vendor: ${vendorText}` : '',
    job.questions ? `Questions: ${asText(job.questions)}` : ''
  ].filter(Boolean);

  rows.push({
    json: {
      external_id: externalId,
      source: 'Apify Upwork',
      source_url: sourceUrl,
      title: job.title || '',
      company_name: 'Upwork Client',
      location: 'Remote freelance',
      region: 'Remote freelance',
      description: descriptionParts.join('\n\n'),
      employment_type: 'Freelance',
      salary_min: null,
      salary_max: null,
      currency: '',
      posted_at: job.publishedAt || job.createdAt || null,
      discovered_at: new Date().toISOString(),
      stage: 'Discovered',
      application_cost: job.applicationCost ?? null,
      custom_job_score: job.customJobScore ?? null,
      category: job.category || '',
      skills: skillsText,
      budget: budgetText,
      raw_payload: job
    }
  });
}

return rows;

return items.map((item) => {
  const original = item.pairedItem ? $items('Build OpenAI Apify Request')[item.pairedItem.item].json.opportunity : {};
  const response = item.json;
  const text = response.output_text || response.output?.[0]?.content?.[0]?.text || '{}';
  let score = {};

  try {
    score = typeof text === 'string' ? JSON.parse(text) : text;
  } catch (error) {
    score = {
      score: 0,
      priority: 'Low',
      strengths: [],
      risks: ['OpenAI response could not be parsed'],
      suggested_positioning: '',
      next_action: 'Review manually',
      reasoning: error.message
    };
  }

  return {
    json: {
      ...original,
      score: score.score,
      priority: score.priority,
      strengths: Array.isArray(score.strengths) ? score.strengths.join('\n') : String(score.strengths || ''),
      risks: Array.isArray(score.risks) ? score.risks.join('\n') : String(score.risks || ''),
      positioning: score.suggested_positioning || '',
      next_action: score.next_action || '',
      reasoning: score.reasoning || '',
      stage: Number(score.score) >= 70 ? 'Evaluated' : 'Archived'
    }
  };
});

return items.map((item) => ({
  json: {
    opportunity: item.json,
    openaiBody: {
      model: $env.OPENAI_SCORING_MODEL || 'gpt-5-mini',
      input: [
        {
          role: 'system',
          content: 'You evaluate Upwork freelance leads for Farshad, an advanced quantitative researcher and AI/ML engineer. Return strict JSON only.'
        },
        {
          role: 'user',
          content: 'Evaluate this Upwork opportunity. Favor projects involving prediction markets, Kalshi, Polymarket, sports betting, Betfair, trading automation, market microstructure, crypto trading, Python trading systems, time-series ML, reinforcement learning, low-latency systems, or financial machine learning. Penalize vague projects, low-budget clients, and projects asking for full production trading bots without controls. Return JSON with score, priority, strengths, risks, suggested_positioning, next_action, and reasoning. Opportunity: ' + JSON.stringify(item.json)
        }
      ],
      text: {
        format: {
          type: 'json_schema',
          name: 'opportunity_score',
          schema: {
            type: 'object',
            additionalProperties: false,
            properties: {
              score: { type: 'number' },
              priority: { type: 'string' },
              strengths: { type: 'array', items: { type: 'string' } },
              risks: { type: 'array', items: { type: 'string' } },
              suggested_positioning: { type: 'string' },
              next_action: { type: 'string' },
              reasoning: { type: 'string' }
            },
            required: ['score', 'priority', 'strengths', 'risks', 'suggested_positioning', 'next_action', 'reasoning']
          }
        }
      }
    }
  }
}));
